<script setup lang="ts">
import { ref,onMounted } from 'vue';import { RouterLink } from 'vue-router';import { fetchOrders,cancelOrder,refundOrder } from '@/services/trade';import { formatMoney } from '@/lib/currency';import type { TradeOrder } from '@/types/trade'
const orders=ref<TradeOrder[]>([]),errorMessage=ref('');async function load(){try{orders.value=(await fetchOrders()).list}catch(e){errorMessage.value=e instanceof Error?e.message:'订单加载失败'}}async function cancel(o:TradeOrder){await cancelOrder(o.id);await load()}async function refund(o:TradeOrder){const reason=window.prompt('退款原因','行程有变');if(reason){await refundOrder(o.id,reason);await load()}}onMounted(load)
</script><template><section class="page-section"><div class="page-header"><div><p class="eyebrow">我的订单</p><h1>支付状态和订单状态分开看，账才不会乱。</h1></div></div><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><div class="rank-list"><article v-for="o in orders" :key="o.id" class="content-card rank-item"><img :src="o.coverImage" :alt="o.dealTitle"><div class="rank-item__body"><RouterLink :to="`/user/orders/${o.id}`"><h2>{{o.dealTitle}}</h2></RouterLink><p>{{o.shopName}} · 数量 {{o.quantity}} · {{formatMoney(o.amount,o.currency)}}</p><span class="status-pill">{{o.payStatusText}}</span></div><div class="form-actions"><button v-if="o.payStatus===0&&o.status===1" class="secondary-button" @click="cancel(o)">取消</button><button v-if="o.payStatus===1" class="secondary-button" @click="refund(o)">退款</button></div></article></div></section></template>
